questionText:
Considérez le code suivant : &lt;pre&gt;<code>interface IVolant { void Deplacer(); }
interface INageur { void Deplacer(); }
class Canard : IVolant, INageur {
  void IVolant.Deplacer() { Console.WriteLine("Vole"); }
  void INageur.Deplacer() { Console.WriteLine("Nage"); }
}

Canard c = new Canard();
c.Deplacer(); // Ligne A
((IVolant)c).Deplacer(); // Ligne B</code>&lt;/pre&gt; Que se passe-t-il ?
